import sqlite3
import os

def find_sqlite_dbs(path='/'):
    dbs = []
    for root, dirs, files in os.walk(path):
        for file in files:
            if file.endswith('.sqlite') or file.endswith('.db'):
                dbs.append(os.path.join(root, file))
    return dbs

print(find_sqlite_dbs('/'))

